const payload = $input.first()?.json?.body ?? $input.first()?.json ?? {};
const cars = Array.isArray(payload.items) ? payload.items : [];
const store = $getWorkflowStaticData('global');
if (!store.seenIds || typeof store.seenIds !== 'object') store.seenIds = {};
const fresh = [];

for (const car of cars) {
  const leadId = String(car.lead_id ?? car.id ?? '').trim();
  const url = String(car.url ?? car.link ?? '').trim();
  if (!leadId || !url) continue;
  if (store.seenIds[leadId]) continue;

  store.seenIds[leadId] = {
    firstSeenAt: new Date().toISOString(),
    title: String(car.title ?? car.modelo ?? 'Sin titulo'),
    url,
  };

  fresh.push({
    json: {
      lead_id: leadId,
      title: String(car.title ?? car.modelo ?? 'Sin titulo'),
      price: String(car.price ?? car.precio ?? 'No disponible'),
      mileage_km: String(car.mileage_km ?? car.km ?? 'No disponible'),
      year: String(car.year ?? car.ano ?? 'No disponible'),
      url,
      image_url: String(car.image_url ?? ''),
      location: String(car.location ?? 'Ubicacion no disponible'),
      source: String(car.source ?? 'AutoScout24'),
    },
  });
}

return fresh;
